SELECT publishers.pub_name, authors.au_lname, authors.au_fname, titleauthor.royaltyper AS royalty, sales.qty, (sales.qty * titleauthor.royaltyper / 100) AS royalty_amount FROM publishers JOIN titles ON publishers.pub_id = titles.pub_id JOIN titleauthor ON titles.title_id = titleauthor.title_id JOIN authors ON titleauthor.au_id = authors.au_id JOIN sales ON titles.title_id = sales.title_id WHERE (publishers.pub_name = 'Algodata Infosystems') AND (authors.contract = 1) AND (titleauthor.royaltyper = 100)
